// ── Lecture du body ──────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;
const deployment_id    = body.deployment_id;
const message_override = body.message_override || '';
const isTest           = body.test === true;
const testDest         = body.test_destinataire || null;

// ── Secrets fournis par le proxy serveur Vercel ──────────────
const SUPA_KEY     = body.supa_key;
const TWILIO_SID   = body.twilio_sid;
const TWILIO_TOKEN = body.twilio_token;
if (!SUPA_KEY || !TWILIO_SID || !TWILIO_TOKEN) {
  return { json: { skip: true, reason: 'Cles manquantes dans le body (utilise le proxy du portail)' } };
}

const H = { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json' };

// ── 0. TEST ou REEL : preparer les donnees ──────────────────
let ciblages = [];
let reservistesRaw = [];

if (isTest) {
  if (!testDest?.email && !testDest?.telephone) {
    return { json: { skip: true, reason: 'TEST sans email ni telephone' } };
  }
  if (!deployment_id) {
    return { json: { skip: true, reason: 'TEST sans deployment_id' } };
  }
  console.log('Mode TEST — destinataire unique:', testDest.email, testDest.telephone);
  ciblages = [{ id: 'TEST-CIBLAGE', benevole_id: testDest.benevole_id || 'TEST', statut: 'cible' }];
  reservistesRaw = [{
    benevole_id: testDest.benevole_id || 'TEST',
    prenom:      testDest.prenom || 'Test',
    nom:         testDest.nom || '',
    email:       testDest.email || null,
    telephone:   testDest.telephone || null
  }];
} else {
  const ciblage_ids = body.ciblage_ids || [];
  if (!deployment_id || !ciblage_ids.length) {
    return { json: { skip: true, reason: 'deployment_id ou ciblage_ids manquants' } };
  }
  console.log('Ciblage portail pour deployment:', deployment_id, '| ciblages:', ciblage_ids.length);
  const ciblageFilter = ciblage_ids.map(id => `id.eq.${id}`).join(',');
  ciblages = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/ciblages?or=(${ciblageFilter})&select=id,benevole_id,statut`,
    headers: H
  });
  if (!ciblages?.length) {
    return { json: { skip: true, reason: 'Aucun ciblage trouve pour ces IDs' } };
  }
  const benevoleIds = [...new Set(ciblages.map(c => c.benevole_id))];
  const reservisteFilter = benevoleIds.map(id => `benevole_id.eq.${id}`).join(',');
  reservistesRaw = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/reservistes?or=(${reservisteFilter})&select=benevole_id,prenom,nom,email,telephone`,
    headers: H
  });
  console.log('Reservistes charges:', reservistesRaw?.length || 0);
}

// ── 1. Charger le deploiement ─────────────────────────────────
const deps = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/deployments?id=eq.${deployment_id}&select=id,identifiant,nom,lieu,date_debut,date_fin,branding,mode_dates,heures_limite_reponse`,
  headers: H
});
const dep = deps?.[0] || {};
console.log('Deploiement:', dep.nom, '| Lieu:', dep.lieu, '| Branding:', dep.branding);

const dateDebutAff = dep.date_debut ? dep.date_debut.split('-').reverse().join('/') : '';
const branding = (dep.branding || 'RIUSC').toUpperCase();

const rMap = {};
for (const r of (reservistesRaw || [])) rMap[r.benevole_id] = r;

// ── Parser le message_override pour extraire SMS et courriel ─
// Convention: ---SMS---\n<texte sms>\n---FIN---
// Si pas de markers, on utilise le message entier pour les deux.
function extractSmsAndEmail(msg) {
  const m = msg.match(/---SMS---([\s\S]*?)---FIN---/);
  if (m) {
    const sms = m[1].trim();
    const emailClean = msg.replace(m[0], '').trim();
    return { sms, email: emailClean };
  }
  return { sms: msg, email: msg };
}

const { sms: smsCore, email: emailCore } = extractSmsAndEmail(message_override);

const timestamp_envoi = new Date().toISOString();

// ── 2. Envoyer SMS ───────────────────────────────────────────
const resultats = [];

for (const ciblage of ciblages) {
  const r = rMap[ciblage.benevole_id];
  if (!r?.prenom) {
    console.log('Reserviste introuvable pour benevole_id:', ciblage.benevole_id);
    continue;
  }

  // Personnaliser le SMS avec le prenom du destinataire
  // Remplace 'Bonjour,' en debut de message par 'Bonjour <prenom>,'
  const smsPrefix = isTest ? '[TEST] ' : '';
  const smsPersonalized = smsCore.replace(/^Bonjour,/, `Bonjour ${r.prenom},`);
  const smsBody = smsPrefix + smsPersonalized;

  if (r.telephone) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_SID}/Messages.json`,
        auth: { username: TWILIO_SID, password: TWILIO_TOKEN },
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `From=%2B14388073137&To=%2B1${r.telephone.replace(/\D/g, '')}&Body=${encodeURIComponent(smsBody)}`
      });
      console.log(`${isTest ? 'TEST ' : ''}SMS ciblage envoye a`, r.telephone);
    } catch (e) {
      console.log('Erreur SMS', r.benevole_id, e.message);
    }
  }

  // Personnaliser le texte email aussi
  const emailPersonalized = emailCore.replace(/^Bonjour,/, `Bonjour ${r.prenom},`);

  resultats.push({
    isTest,
    supa_key:        SUPA_KEY,
    ciblage_id:      ciblage.id,
    benevole_id:     r.benevole_id,
    prenom:          r.prenom,
    nom:             r.nom,
    email:           r.email,
    telephone:       r.telephone,
    nom_deploiement: (isTest ? '[TEST] ' : '') + (dep.nom || ''),
    lieu:            dep.lieu || '',
    date_debut:      dateDebutAff,
    branding,
    message_email:   emailPersonalized,
    deployment_id,
    timestamp_envoi
  });
}

if (!resultats.length) {
  return { json: { skip: true, reason: 'Aucun reserviste avec profil complet trouve' } };
}

return resultats.map(r => ({ json: r }));

// Recupere les donnees du node 2 (pas $input.item.json qui est la reponse SMTP)
const data = $('2. Charger + SMS').item.json;

if (data.skip) return { json: { skip: true } };

// Mode TEST : on ne touche PAS a la DB
if (data.isTest) {
  console.log('TEST — skip update DB pour', data.benevole_id);
  return { json: { success: true, benevole_id: data.benevole_id, ciblage_id: data.ciblage_id, timestamp: data.timestamp_envoi, isTest: true } };
}

const SUPA_KEY = data.supa_key;
if (!SUPA_KEY) {
  console.log('supa_key manquante — skip update DB');
  return { json: { skip: true, reason: 'supa_key manquante' } };
}

const H = { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/ciblages?id=eq.${data.ciblage_id}`,
    headers: H,
    body: JSON.stringify({
      statut: 'notifie',
      updated_at: data.timestamp_envoi
    })
  });
  console.log('Supabase ciblage notifie:', data.benevole_id, data.ciblage_id);
} catch (e) {
  console.log('Erreur Supabase update ciblage:', e.message);
}

return { json: { success: true, benevole_id: data.benevole_id, ciblage_id: data.ciblage_id, timestamp: data.timestamp_envoi } };

const items = $input.all();
const nb_envoyes = items.filter(i => i.json.success).length;
const nb_erreurs = items.filter(i => i.json.skip).length;
const isTest = items.some(i => i.json.isTest);
console.log(`${isTest ? 'TEST ' : ''}Ciblage portail termine: ${nb_envoyes} envoye(s), ${nb_erreurs} ignore(s)`);
return { json: { done: true, nb_envoyes, nb_erreurs, isTest } };
